exercises.solution_code:
#include <iostream>
#include <string>
#include <string_view>

constexpr int SHORT_MAX  = 3;
constexpr int MEDIUM_MAX = 7;

void classify(std::string_view word)
{
    std::cout << "Word: " << word << " (length: " << word.length() << ")\n";

    if (word.length() <= SHORT_MAX)
        std::cout << "Category: short\n";
    else if (word.length() <= MEDIUM_MAX)
        std::cout << "Category: medium\n";
    else
        std::cout << "Category: long\n";
}

int main()
{
    std::string input{};
    std::cin >> input;

    classify(input);

    return 0;
}
